"use client";

import type React from "react";
import {
  createContext,
  useCallback,
  useContext,
  useEffect,
  useMemo,
  useState,
} from "react";
import { toast } from "sonner";
import type { IEvent, IUser } from "@/features/calendar/interfaces";
import type { TCalendarView } from "@/features/calendar/types";
import type { ICalendarContext } from "./calendar-context.types";
import { useCalendarFilterState } from "@/features/calendar/hooks/use-calendar-filter-state";
import { useCalendarSettingsState } from "@/features/calendar/hooks/use-calendar-settings-state";
import { useCalendarEventState } from "../hooks/use-calendar-event-state";
import { useAuth } from "./authContext";
import { canManageEvent } from "@/features/calendar/lib/permissions";
import { getEvents, getUsers, mapViewToSchedulePeriod } from "../requests";

const CalendarContext = createContext({} as ICalendarContext);

type CalendarProviderProps = {
  children: React.ReactNode;
  users: IUser[];
  events: IEvent[];
  view?: TCalendarView;
  badge?: "dot" | "colored";
};

export function CalendarProvider({
  children,
  users,
  events,
  badge = "colored",
  view = "day",
}: CalendarProviderProps) {
  const { token, user, isManager, canManageCalendar } = useAuth();
  const currentUserId = user?.userId;
  const [selectedDate, setSelectedDateState] = useState(new Date());
  const [isLoadingEvents, setIsLoadingEvents] = useState(false);
  const [calendarUsers, setCalendarUsers] = useState<IUser[]>(users);

  const {
    allEvents,
    setEvents,
    addEvent: addEventRaw,
    updateEvent: updateEventRaw,
    removeEvent: removeEventRaw,
    restoreEvent: restoreEventRaw,
    purgeEvent: purgeEventRaw,
  } = useCalendarEventState({
    initialEvents: events,
  });

  const {
    badgeVariant,
    setBadgeVariant,
    view: currentView,
    setView,
    use24HourFormat,
    toggleTimeFormat,
    agendaModeGroupBy,
    setAgendaModeGroupBy,
  } = useCalendarSettingsState({
    initialBadge: badge,
    initialView: view,
  });

  const activeEvents = useMemo(
    () => allEvents.filter((event) => !event.deletedAt),
    [allEvents],
  );

  const deletedEvents = useMemo(
    () => allEvents.filter((event) => !!event.deletedAt),
    [allEvents],
  );

  const addEvent = useCallback(
    (event: IEvent) => {
      if (!canManageCalendar) {
        toast.error("Perfil atendente possui acesso somente leitura.");
        return;
      }

      if (!canManageEvent(event.user?.id, currentUserId, isManager)) {
        toast.error("Somente perfis com permissao de gestao podem criar eventos.");
        return;
      }

      addEventRaw(event);
    },
    [addEventRaw, canManageCalendar, currentUserId, isManager],
  );

  const updateEvent = useCallback(
    (event: IEvent) => {
      if (!canManageCalendar) {
        toast.error("Perfil atendente possui acesso somente leitura.");
        return;
      }

      const existingEvent = allEvents.find((current) => current.id === event.id);
      const ownerId = existingEvent?.user?.id ?? event.user?.id;

      if (!canManageEvent(ownerId, currentUserId, isManager)) {
        toast.error("Somente perfis com permissao de gestao podem editar eventos.");
        return;
      }

      updateEventRaw(event);
    },
    [allEvents, canManageCalendar, currentUserId, isManager, updateEventRaw],
  );

  const removeEvent = useCallback(
    (eventId: number, deletedBy?: string) => {
      if (!canManageCalendar) {
        toast.error("Perfil atendente possui acesso somente leitura.");
        return;
      }

      const event = allEvents.find((current) => current.id === eventId);
      const ownerId = event?.user?.id;

      if (!canManageEvent(ownerId, currentUserId, isManager)) {
        toast.error("Somente perfis com permissao de gestao podem excluir eventos.");
        return;
      }

      removeEventRaw(eventId, deletedBy);
    },
    [allEvents, canManageCalendar, currentUserId, isManager, removeEventRaw],
  );

  const restoreEvent = useCallback(
    (eventId: number) => {
      if (!canManageCalendar) {
        toast.error("Perfil atendente possui acesso somente leitura.");
        return;
      }

      const event = allEvents.find((current) => current.id === eventId);
      const ownerId = event?.user?.id;

      if (!canManageEvent(ownerId, currentUserId, isManager)) {
        toast.error("Somente perfis com permissao de gestao podem restaurar eventos.");
        return;
      }

      restoreEventRaw(eventId);
    },
    [allEvents, canManageCalendar, currentUserId, isManager, restoreEventRaw],
  );

  const purgeEvent = useCallback(
    (eventId: number) => {
      if (!canManageCalendar) {
        toast.error("Perfil atendente possui acesso somente leitura.");
        return;
      }

      const event = allEvents.find((current) => current.id === eventId);
      const ownerId = event?.user?.id;

      if (!canManageEvent(ownerId, currentUserId, isManager)) {
        toast.error("Somente perfis com permissao de gestao podem remover eventos.");
        return;
      }

      purgeEventRaw(eventId);
    },
    [allEvents, canManageCalendar, currentUserId, isManager, purgeEventRaw],
  );

  const {
    selectedUserIds,
    setSelectedUserIds,
    selectedColors,
    selectedStatuses,
    selectedTypes,
    selectedPriorities,
    filterEventsBySelectedColors,
    filterEventsBySelectedStatus,
    filterEventsBySelectedType,
    filterEventsBySelectedPriority,
    filterEventsBySelectedUser,
    filteredEvents,
    clearFilter,
  } = useCalendarFilterState({
    events: activeEvents,
  });

  const setSelectedDate = (date: Date | undefined) => {
    if (!date) return;
    setSelectedDateState(date);
  };

  useEffect(() => {
    let isActive = true;

    async function syncEvents() {
      if (!token) {
        setCalendarUsers([]);
        setEvents([]);
        setIsLoadingEvents(false);
        return;
      }

      setIsLoadingEvents(true);

      try {
        const nextUsers = await getUsers();
        const nextEvents = await getEvents({
          period: mapViewToSchedulePeriod(currentView),
          referenceDate: selectedDate,
          users: nextUsers,
        });

        if (isActive) {
          setCalendarUsers(nextUsers);
          setEvents(nextEvents);
        }
      } catch (error) {
        console.error("Erro ao carregar agendamentos:", error);
        toast.error("Sem conexao com o backend. Verifique se a API esta online.");
      } finally {
        if (isActive) {
          setIsLoadingEvents(false);
        }
      }
    }

    void syncEvents();

    return () => {
      isActive = false;
    };
  }, [currentView, selectedDate, setEvents, token]);

  const value: ICalendarContext = {
    selectedDate,
    setSelectedDate,
    selectedUserIds,
    setSelectedUserIds,
    badgeVariant,
    setBadgeVariant,
    users: calendarUsers,
    selectedColors,
    selectedStatuses,
    selectedTypes,
    selectedPriorities,
    filterEventsBySelectedColors,
    filterEventsBySelectedStatus,
    filterEventsBySelectedType,
    filterEventsBySelectedPriority,
    filterEventsBySelectedUser,
    events: filteredEvents,
    deletedEvents,
    isLoadingEvents,
    view: currentView,
    use24HourFormat,
    toggleTimeFormat,
    setView,
    agendaModeGroupBy,
    setAgendaModeGroupBy,
    addEvent,
    updateEvent,
    removeEvent,
    restoreEvent,
    purgeEvent,
    clearFilter,
  };

  return (
    <CalendarContext.Provider value={value}>{children}</CalendarContext.Provider>
  );
}

export function useCalendar(): ICalendarContext {
  const context = useContext(CalendarContext);

  if (!context) {
    throw new Error("useCalendar must be used within a CalendarProvider.");
  }

  return context;
}

"use client";

import React, {
  createContext,
  type ReactNode,
  useCallback,
  useContext,
  useRef,
  useState,
  useMemo,
} from "react";
import { toast } from "sonner";
import { useAuth } from "@/features/calendar/contexts/authContext";
import { useCalendar } from "@/features/calendar/contexts/calendar-context";
import type { IEvent } from "@/features/calendar/interfaces";
import { canManageEvent } from "@/features/calendar/lib/permissions";

interface DragDropContextType {
  draggedEvent: IEvent | null;
  isDragging: boolean;
  startDrag: (event: IEvent) => void;
  endDrag: () => void;
  handleEventDrop: (date: Date, hour?: number, minute?: number) => void;
}

interface DndProviderProps {
  children: ReactNode;
}

const DragDropContext = createContext<DragDropContextType | undefined>(
  undefined,
);

export function DndProvider({ children }: DndProviderProps) {
  const { updateEvent } = useCalendar();
  const { user, isManager } = useAuth();
  const [dragState, setDragState] = useState<{
    draggedEvent: IEvent | null;
    isDragging: boolean;
  }>({ draggedEvent: null, isDragging: false });

  const onEventDroppedRef = useRef<
    ((event: IEvent, newStartDate: Date, newEndDate: Date) => void) | null
  >(null);

  const startDrag = useCallback((event: IEvent) => {
    setDragState({ draggedEvent: event, isDragging: true });
  }, []);

  const endDrag = useCallback(() => {
    setDragState({ draggedEvent: null, isDragging: false });
  }, []);

  const calculateNewDates = useCallback(
    (event: IEvent, targetDate: Date, hour?: number, minute?: number) => {
      const originalStart = new Date(event.startDate);
      const originalEnd = new Date(event.endDate);
      const duration = originalEnd.getTime() - originalStart.getTime();

      const newStart = new Date(targetDate);
      if (hour !== undefined) {
        newStart.setHours(hour, minute || 0, 0, 0);
      } else {
        newStart.setHours(
          originalStart.getHours(),
          originalStart.getMinutes(),
          0,
          0,
        );
      }

      return {
        newStart,
        newEnd: new Date(newStart.getTime() + duration),
      };
    },
    [],
  );

  const isSamePosition = useCallback((date1: Date, date2: Date) => {
    return date1.getTime() === date2.getTime();
  }, []);

  const handleEventDrop = useCallback(
    (targetDate: Date, hour?: number, minute?: number) => {
      const { draggedEvent } = dragState;
      if (!draggedEvent) return;
      if (!canManageEvent(draggedEvent.user?.id, user?.userId, isManager)) {
        toast.error("Perfil atendente possui acesso somente leitura.");
        endDrag();
        return;
      }

      const { newStart, newEnd } = calculateNewDates(
        draggedEvent,
        targetDate,
        hour,
        minute,
      );
      const originalStart = new Date(draggedEvent.startDate);

      // Check if dropped in same position
      if (isSamePosition(originalStart, newStart)) {
        endDrag();
        return;
      }

      // Instantly update event
      const callback = onEventDroppedRef.current;
      if (callback) {
        callback(draggedEvent, newStart, newEnd);
      }
      endDrag();
    },
    [dragState, calculateNewDates, isSamePosition, endDrag, user, isManager],
  );

  // Default event update handler
  const handleEventUpdate = useCallback(
    (event: IEvent, newStartDate: Date, newEndDate: Date) => {
      try {
        const updatedEvent = {
          ...event,
          startDate: newStartDate.toISOString(),
          endDate: newEndDate.toISOString(),
        };
        updateEvent(updatedEvent);
        toast.success("Event updated successfully");
      } catch {
        toast.error("Failed to update event");
      }
    },
    [updateEvent],
  );

  // Set default callback
  React.useEffect(() => {
    onEventDroppedRef.current = handleEventUpdate;
  }, [handleEventUpdate]);

  const contextValue = useMemo(
    () => ({
      draggedEvent: dragState.draggedEvent,
      isDragging: dragState.isDragging,
      startDrag,
      endDrag,
      handleEventDrop,
    }),
    [dragState, startDrag, endDrag, handleEventDrop],
  );

  return (
    <DragDropContext.Provider value={contextValue}>
      {children}
    </DragDropContext.Provider>
  );
}

export function useDragDrop() {
  const context = useContext(DragDropContext);
  if (!context) {
    throw new Error("useDragDrop must be used within a DragDropProvider");
  }
  return context;
}

import { TrashIcon } from "lucide-react";
import { toast } from "sonner";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { Button } from "@/components/ui/button";
import { useCalendar } from "@/features/calendar/contexts/calendar-context";

interface DeleteEventDialogProps {
  eventId: number;
}

export default function DeleteEventDialog({ eventId }: DeleteEventDialogProps) {
  const { removeEvent } = useCalendar();

  const deleteEvent = () => {
    try {
      removeEvent(eventId);
      toast.success("Event deleted successfully.");
    } catch {
      toast.error("Error deleting event.");
    }
  };

  if (!eventId) {
    return null;
  }

  return (
    <AlertDialog>
      <AlertDialogTrigger asChild>
        <Button variant="destructive">
          <TrashIcon />
          Delete
        </Button>
      </AlertDialogTrigger>
      <AlertDialogContent>
        <AlertDialogHeader>
          <AlertDialogTitle>Are you absolutely sure?</AlertDialogTitle>
          <AlertDialogDescription>
            This action cannot be undone. This will permanently delete your
            event and remove event data from our servers.
          </AlertDialogDescription>
        </AlertDialogHeader>
        <AlertDialogFooter>
          <AlertDialogCancel>Cancel</AlertDialogCancel>
          <AlertDialogAction onClick={deleteEvent}>Continue</AlertDialogAction>
        </AlertDialogFooter>
      </AlertDialogContent>
    </AlertDialog>
  );
}

"use client";

import { format, parseISO } from "date-fns";
import { ptBR } from "date-fns/locale";
import { Calendar, Clock, Text, User } from "lucide-react";
import type { ReactNode } from "react";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogClose,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { ScrollArea } from "@/components/ui/scroll-area";
import { useCalendar } from "@/features/calendar/contexts/calendar-context";
import { useAuth } from "@/features/calendar/contexts/authContext";
import { AddEditEventDialog } from "@/features/calendar/dialogs/add-edit-event-dialog";
import { formatTime, toCapitalize } from "@/features/calendar/helpers";
import type { IEvent } from "@/features/calendar/interfaces";

interface IProps {
  event: IEvent;
  children: ReactNode;
}

export function EventDetailsDialog({ event, children }: IProps) {
  const startDate = parseISO(event.startDate);
  const endDate = parseISO(event.endDate);
  const scheduledAt = event.createdAt ? parseISO(event.createdAt) : null;
  const { use24HourFormat, removeEvent } = useCalendar();
  const { user, canManageCalendar } = useAuth();
  const schedulerRoleLabel =
    typeof event.scheduledBy?.permissionLevel === "number" &&
    event.scheduledBy.permissionLevel >= 2
      ? "Gerente"
      : "Usuario";

  const deleteEvent = (eventId: number) => {
    try {
      removeEvent(eventId, user?.name);
      toast.success("Event deleted successfully.");
    } catch {
      toast.error("Error deleting event.");
    }
  };

  return (
    <Dialog>
      <DialogTrigger asChild>{children}</DialogTrigger>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>{event.title}</DialogTitle>
        </DialogHeader>

        <ScrollArea className="max-h-[80vh]">
          <div className="space-y-4 p-4">
            <div className="flex items-start gap-2">
              <User className="mt-1 size-4 shrink-0 text-muted-foreground" />
              <div>
                <p className="text-sm font-medium">Responsible</p>
                <p className="text-sm text-muted-foreground">{event.user.name}</p>
              </div>
            </div>

            <div className="flex items-start gap-2">
              <User className="mt-1 size-4 shrink-0 text-muted-foreground" />
              <div>
                <p className="text-sm font-medium">Agendado por ({schedulerRoleLabel})</p>
                <p className="text-sm text-muted-foreground">
                  {event.scheduledBy?.name ?? "Nao informado"}
                </p>
                {event.scheduledBy?.mail && (
                  <p className="text-xs text-muted-foreground">
                    {event.scheduledBy.mail}
                  </p>
                )}
                {typeof event.scheduledBy?.permissionLevel === "number" && (
                  <p className="text-xs text-muted-foreground">
                    Nivel de permissao: {event.scheduledBy.permissionLevel}
                  </p>
                )}
                <p className="text-xs text-muted-foreground">
                  Agendado em:{" "}
                  {scheduledAt
                    ? format(
                        scheduledAt,
                        use24HourFormat ? "dd/MM/yyyy HH:mm" : "dd/MM/yyyy hh:mm a",
                      )
                    : "Nao informado"}
                </p>
              </div>
            </div>

            <div className="flex items-start gap-2">
              <Calendar className="mt-1 size-4 shrink-0 text-muted-foreground" />
              <div>
                <p className="text-sm font-medium">Start Date</p>
                <p className="text-sm text-muted-foreground">
                  {toCapitalize(
                    format(startDate, "EEEE dd MMMM", { locale: ptBR }).replace(
                      "-feira",
                      "",
                    ),
                  )}
                  <span className="mx-1">as</span>
                  {formatTime(parseISO(event.startDate), use24HourFormat)}
                </p>
              </div>
            </div>

            <div className="flex items-start gap-2">
              <Clock className="mt-1 size-4 shrink-0 text-muted-foreground" />
              <div>
                <p className="text-sm font-medium">End Date</p>
                <p className="text-sm text-muted-foreground">
                  {toCapitalize(
                    format(endDate, "EEEE dd MMMM", { locale: ptBR }).replace(
                      "-feira",
                      "",
                    ),
                  )}
                  <span className="mx-1">as</span>
                  {formatTime(parseISO(event.endDate), use24HourFormat)}
                </p>
              </div>
            </div>

            <div className="flex items-start gap-2">
              <Text className="mt-1 size-4 shrink-0 text-muted-foreground" />
              <div>
                <p className="text-sm font-medium">Description</p>
                <p className="text-sm text-muted-foreground">{event.description}</p>
              </div>
            </div>

            {(event.customerId || event.customerPhone) && (
              <div className="flex items-start gap-2">
                <Text className="mt-1 size-4 shrink-0 text-muted-foreground" />
                <div>
                  <p className="text-sm font-medium">Cliente</p>
                  {event.customerId && (
                    <p className="text-sm text-muted-foreground">
                      ID: {event.customerId}
                    </p>
                  )}
                  {event.customerPhone && (
                    <p className="text-sm text-muted-foreground">
                      Telefone: {event.customerPhone}
                    </p>
                  )}
                </div>
              </div>
            )}
          </div>
        </ScrollArea>

        <div className="flex justify-end gap-2">
          {canManageCalendar ? (
            <>
              <AddEditEventDialog event={event}>
                <Button variant="outline">Edit</Button>
              </AddEditEventDialog>
              <Button
                variant="destructive"
                onClick={() => {
                  deleteEvent(event.id);
                }}
              >
                Delete
              </Button>
            </>
          ) : (
            <div className="rounded-md border border-orange-200 bg-orange-50 px-4 py-3 text-sm text-orange-700">
              Perfil atendente possui acesso somente leitura.
            </div>
          )}
        </div>
        <DialogClose />
      </DialogContent>
    </Dialog>
  );
}

import { format, parseISO } from "date-fns";
import { ptBR } from "date-fns/locale";
import type { ReactNode } from "react";
import {
  Modal,
  ModalContent,
  ModalHeader,
  ModalTitle,
  ModalTrigger,
} from "@/components/ui/responsive-modal";
import { Button } from "@/components/ui/button";
import { useCalendar } from "@/features/calendar/contexts/calendar-context";
import { useAuth } from "@/features/calendar/contexts/authContext";
import type { IEvent } from "@/features/calendar/interfaces";
import { EventBullet } from "@/features/calendar/views/month-view/event-bullet";
import { EventDetailsDialog } from "@/features/calendar/dialogs/event-details-dialog";
import { AddEditEventDialog } from "@/features/calendar/dialogs/add-edit-event-dialog";
import { EventItem } from "@/features/calendar/components/event-item";

interface EventListDialogProps {
  date: Date;
  events: IEvent[];
  maxVisibleEvents?: number;
  children?: ReactNode;
}

export function EventListDialog({
  date,
  events,
  maxVisibleEvents = 3,
  children,
}: EventListDialogProps) {
  const cellEvents = events;
  const hiddenEventsCount = Math.max(cellEvents.length - maxVisibleEvents, 0);
  const { use24HourFormat, removeEvent } = useCalendar();
  const { user, canManageCalendar } = useAuth();

  const defaultTrigger = (
    <span className="cursor-pointer text-black">
      <span className="sm:hidden">+{hiddenEventsCount}</span>
      <span className="hidden rounded-xl border border-slate-400 bg-slate-300 px-3 py-1 text-black shadow-sm sm:inline">
        {hiddenEventsCount}
        <span className="mx-1">mais...</span>
      </span>
    </span>
  );

  return (
    <Modal>
      <ModalTrigger asChild>{children || defaultTrigger}</ModalTrigger>
      <ModalContent className="bg-slate-200 text-slate-950 dark:bg-background sm:max-w-106.25">
        <ModalHeader>
          <ModalTitle className="my-2">
            <div className="flex items-center gap-2">
              <EventBullet
                color={cellEvents[0]?.color ?? "blue"}
                className="shadow-sm"
              />
              <p className="text-sm font-semibold italic text-slate-950 dark:text-foreground">
                Eventos em{" "}
                {format(date, "EEEE, d 'de' MMMM 'de' yyyy", { locale: ptBR })}
              </p>
            </div>
          </ModalTitle>
        </ModalHeader>
        <div className="max-h-[60vh] space-y-3 overflow-y-auto px-2 pb-4">
          {cellEvents.length > 0 ? (
            cellEvents.map((event) => {
              return (
                <div
                  key={event.id}
                  className="space-y-2 rounded-2xl border border-slate-400 bg-white p-3 text-slate-950 shadow-lg dark:border-border dark:bg-card dark:text-card-foreground"
                >
                  <EventDetailsDialog event={event}>
                    <EventItem
                      title={event.title}
                      startDate={event.startDate}
                      endDate={event.endDate}
                      status={event.status}
                      type={event.type}
                      priority={event.priority}
                      secondaryLabel={event.user?.name}
                      description={event.description}
                      use24HourFormat={use24HourFormat}
                    />
                  </EventDetailsDialog>

                  <div className="rounded-lg border border-slate-200 dark:border-white/20 px-3 py-2 text-xs font-semibold text-black dark:text-orange-100">
                    <p>
                      Agendado por: {event.scheduledBy?.name ?? "Nao informado"}
                    </p>
                    <p>
                      Criado em:{" "}
                      {event.createdAt
                        ? format(parseISO(event.createdAt), "dd/MM/yyyy HH:mm")
                        : "Nao informado"}
                    </p>
                  </div>

                  <div className="flex flex-wrap gap-2">
                    {canManageCalendar && (
                      <AddEditEventDialog event={event}>
                        <Button
                          size="sm"
                          variant="secondary"
                          className="border-slate-300 bg-slate-100 text-slate-900 hover:bg-slate-200 dark:border-slate-700 dark:bg-slate-700 dark:text-white dark:hover:bg-slate-800"
                        >
                          Editar
                        </Button>
                      </AddEditEventDialog>
                    )}

                    {canManageCalendar && (
                      <Button
                        size="sm"
                        variant="destructive"
                        className="bg-red-600 text-white hover:bg-red-700"
                        onClick={() => removeEvent(event.id, user?.name)}
                      >
                        Excluir
                      </Button>
                    )}
                  </div>
                </div>
              );
            })
          ) : (
            <p className="text-sm text-muted-foreground">
              Nenhum evento nesta data.
            </p>
          )}
        </div>
      </ModalContent>
    </Modal>
  );
}

import { motion } from "framer-motion";
import type React from "react";
import type { ReactNode } from "react";
import { useAuth } from "@/features/calendar/contexts/authContext";
import { useDragDrop } from "@/features/calendar/contexts/dnd-context";
import type { IEvent } from "@/features/calendar/interfaces";
import { canManageEvent } from "@/features/calendar/lib/permissions";

interface DraggableEventProps {
  event: IEvent;
  children: ReactNode;
  className?: string;
}

export function DraggableEvent({
  event,
  children,
  className,
}: DraggableEventProps) {
  const { startDrag, endDrag, isDragging, draggedEvent } = useDragDrop();
  const { user, isManager } = useAuth();
  const canModify = canManageEvent(event.user?.id, user?.userId, isManager);

  const isCurrentlyDragged = isDragging && draggedEvent?.id === event.id;

  const handleClick = (e: React.MouseEvent<HTMLDivElement>) => {
    e.stopPropagation();
  };

  return (
    <motion.div
      className={`${className || ""} ${isCurrentlyDragged ? "opacity-50 cursor-grabbing" : canModify ? "cursor-grab" : "cursor-default"}`}
      draggable={canModify}
      onClick={(e: React.MouseEvent<HTMLDivElement>) => handleClick(e)}
      onDragStart={(e) => {
        if (!canModify) return;
        (e as DragEvent).dataTransfer!.setData(
          "text/plain",
          event.id.toString(),
        );
        startDrag(event);
      }}
      onDragEnd={() => {
        if (canModify) {
          endDrag();
        }
      }}
    >
      {children}
    </motion.div>
  );
}

import React, { type ReactNode } from "react";
import { useDragDrop } from "@/features/calendar/contexts/dnd-context";

interface DroppableAreaProps {
  date: Date;
  hour?: number;
  minute?: number;
  children: ReactNode;
  className?: string;
}

export function DroppableArea({
  date,
  hour,
  minute,
  children,
  className,
}: DroppableAreaProps) {
  const { handleEventDrop, isDragging } = useDragDrop();

  return (
    <div
      // biome-ignore lint/a11y/useSemanticElements: Using gridcell role for CSS grid layout where td is not applicable
      role="gridcell"
      aria-label="Droppable area"
      tabIndex={-1}
      className={`${className || ""} ${isDragging ? "drop-target" : ""}`}
      onDragOver={(e) => {
        // Prevent default to allow drop
        e.preventDefault();
        e.currentTarget.classList.add("bg-primary/10");
      }}
      onDragLeave={(e) => {
        e.currentTarget.classList.remove("bg-primary/10");
      }}
      onDrop={(e) => {
        e.preventDefault();
        e.currentTarget.classList.remove("bg-primary/10");
        handleEventDrop(date, hour, minute);
      }}
    >
      {children}
    </div>
  );
}

"use client";

import {
  addMinutes,
  differenceInMinutes,
  format,
  isAfter,
  isBefore,
  parseISO,
} from "date-fns";
import { motion } from "framer-motion";
import { Resizable, type ResizeCallback } from "re-resizable";
import type React from "react";
import { useCallback, useMemo, useState } from "react";
import { cn } from "@/features/calendar/lib/utils";
import { useAuth } from "@/features/calendar/contexts/authContext";
import { useCalendar } from "@/features/calendar/contexts/calendar-context";

import type { IEvent } from "@/features/calendar/interfaces";
import { canManageEvent } from "@/features/calendar/lib/permissions";

interface ResizableEventBlockProps {
  event: IEvent;
  children: React.ReactNode;
  className?: string;
}

const PIXELS_PER_HOUR = 96;
const MINUTES_PER_PIXEL = 60 / PIXELS_PER_HOUR;
const MIN_DURATION = 15; // in minutes

export function ResizableEvent({
  event,
  children,
  className,
}: ResizableEventBlockProps) {
  const { updateEvent, use24HourFormat } = useCalendar();
  const { user, isManager } = useAuth();
  const canResize = canManageEvent(event.user?.id, user?.userId, isManager);

  const [isResizing, setIsResizing] = useState(false);
  const [resizePreview, setResizePreview] = useState<{
    start: string;
    end: string;
  } | null>(null);

  const start = useMemo(() => parseISO(event.startDate), [event.startDate]);
  const end = useMemo(() => parseISO(event.endDate), [event.endDate]);
  const durationInMinutes = useMemo(
    () => differenceInMinutes(end, start),
    [start, end],
  );

  const resizeBoundaries = useMemo(() => {
    const dayStart = new Date(start);
    dayStart.setHours(0, 0, 0, 0);

    const dayEnd = new Date(start);
    dayEnd.setHours(23, 59, 59, 999);

    return { dayStart, dayEnd };
  }, [start]);

  const handleResizeStart = useCallback(() => {
    if (!canResize) return;
    setIsResizing(true);
  }, [canResize]);

  const handleResize: ResizeCallback = useCallback(
    (_, direction, ref) => {
      if (!canResize) return;
      const newHeight = parseInt(ref.style.height, 10);
      const newDuration = Math.max(
        MIN_DURATION,
        Math.round((newHeight + 8) * MINUTES_PER_PIXEL),
      );
      const delta = newDuration - durationInMinutes;

      let newStart = start;
      let newEnd = end;

      if (direction.includes("top")) {
        newStart = addMinutes(start, -delta);
      } else if (direction.includes("bottom")) {
        newEnd = addMinutes(end, delta);
      }

      if (isBefore(newStart, resizeBoundaries.dayStart)) {
        newStart = resizeBoundaries.dayStart;
      }
      if (isAfter(newEnd, resizeBoundaries.dayEnd)) {
        newEnd = resizeBoundaries.dayEnd;
      }

      setResizePreview({
        start: format(newStart, use24HourFormat ? "HH:mm" : "h:mm a"),
        end: format(newEnd, use24HourFormat ? "HH:mm" : "h:mm a"),
      });

      updateEvent({
        ...event,
        startDate: newStart.toISOString(),
        endDate: newEnd.toISOString(),
      });
    },
    [
      start,
      end,
      durationInMinutes,
      resizeBoundaries,
      use24HourFormat,
      updateEvent,
      event,
      canResize,
    ],
  );

  const handleResizeStop = useCallback(() => {
    setIsResizing(false);
    setResizePreview(null);
  }, []);

  const resizeConfig = useMemo(
    () => ({
      minHeight: 15,
      maxHeight: 1440,
      enable: {
        top: canResize,
        bottom: canResize,
        topRight: false,
        bottomRight: false,
        bottomLeft: false,
        topLeft: false,
      },
      handleStyles: {
        top: {
          cursor: "ns-resize",
          height: "8px",
          top: "-4px",
          backgroundColor: "transparent",
        },
        bottom: {
          cursor: "ns-resize",
          height: "8px",
          bottom: "-4px",
          backgroundColor: "transparent",
        },
      },
      handleClasses: {
        top: "transition-colors rounded-sm",
        bottom: "transition-colors rounded-sm",
      },
      onResizeStart: handleResizeStart,
      onResize: handleResize,
      onResizeStop: handleResizeStop,
      className: cn(
        "transition-all duration-200",
        isResizing && "z-50 shadow-lg",
      ),
    }),
    [handleResizeStart, handleResize, handleResizeStop, isResizing, canResize],
  );

  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.95 }}
      animate={{ opacity: 1, scale: 1 }}
      exit={{ opacity: 0, scale: 0.95 }}
      transition={{ duration: 0.2 }}
      className={cn("relative group", className)}
    >
      <Resizable {...resizeConfig}>{children}</Resizable>

      {isResizing && resizePreview && (
        <motion.div
          initial={{ opacity: 0, y: -10 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -10 }}
          className="absolute -top-8 left-1/2 transform -translate-x-1/2 bg-gray-900 text-white text-xs px-2 py-1 rounded shadow-lg z-50 whitespace-nowrap"
        >
          {resizePreview.start} - {resizePreview.end}
        </motion.div>
      )}
    </motion.div>
  );
}

