						{renderSelectedCheck(selectedTypes.includes(type))}
					</DropdownMenuItem>
				))}

				<DropdownMenuSeparator />
				<DropdownMenuLabel>Prioridade</DropdownMenuLabel>
				{EVENT_PRIORITIES.map((priority: TEventPriority) => (
					<DropdownMenuItem
						key={priority}
