				))}

				<DropdownMenuSeparator />
				<DropdownMenuItem
					disabled={!hasActiveFilters}
					className="flex gap-2 cursor-pointer"
					onClick={(e) => {
						e.preventDefault();
						clearFilter();
					}}
				>
					<RefreshCcw className="size-3.5" />
